func QueryParamsBinder(c Context) *ValueBinder {
	return &ValueBinder{
		failFast:	true,
		ValueFunc:	c.QueryParam,
		ValuesFunc: func(sourceParam string) []string {
			values, ok := c.QueryParams()[sourceParam]
			if !ok {
				return nil
			}
			return values
		},
		ErrorFunc:	NewBindingError,
	}
}
